// ValidateCreateAgentDefinitionRequestBody runs the validations defined on
// CreateAgentDefinitionRequestBody
func ValidateCreateAgentDefinitionRequestBody(body *CreateAgentDefinitionRequestBody) (err error) {
	if body.Name == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("name", "body"))
	}
	if body.Description == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("description", "body"))
	}
	if body.Instructions == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("instructions", "body"))
	}
	if body.Name != nil {
		err = goa.MergeErrors(err, goa.ValidatePattern("body.name", *body.Name, "^[a-z0-9_-]{1,128}$"))
	}
	if body.Name != nil {
		if utf8.RuneCountInString(*body.Name) > 40 {
			err = goa.MergeErrors(err, goa.InvalidLengthError("body.name", *body.Name, utf8.RuneCountInString(*body.Name), 40, false))
		}
	}
	return
}

